index.js.content:
const log = {
  info:  (...a) => console.log(...a),
  warn:  (...a) => console.warn(...a),
  error: (...a) => console.error(...a),
};

import "dotenv/config";

import { run } from "@grammyjs/runner";
import { cfg } from "./lib/config.js";

import { safeErr } from "./lib/safeErr.js";

process.on("unhandledRejection", (r) => {
  console.error("UnhandledRejection:", r);
  process.exit(1);
});

process.on("uncaughtException", (e) => {
  console.error("UncaughtException:", e);
  process.exit(1);
});

let runner = null;
let restarting = false;

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

async function startPolling(bot) {
  await bot.api.deleteWebhook({ drop_pending_updates: true });

  let backoff = 2000;
  while (true) {
    try {
      log.info("[polling] start", { concurrency: 1 });
      runner = run(bot, { concurrency: 1 });
      await runner.task();

      // If runner.task resolves, treat it as a stop and restart.
      throw new Error("Polling runner stopped");
    } catch (e) {
      const msg = safeErr(e);

      // 409 Conflict: another getUpdates is running
      if (String(msg).includes("409") || String(msg).toLowerCase().includes("conflict")) {
        log.warn("[polling] conflict; retrying", { backoffMs: backoff, err: msg });
      } else {
        log.error("[polling] failed", { backoffMs: backoff, err: msg });
      }

      try {
        runner?.stop?.();
      } catch {}
      runner = null;

      await sleep(backoff);
      backoff = Math.min(20000, Math.round(backoff * 1.7));
    }
  }
}

async function boot() {
  log.info("[boot] start", {
    TELEGRAM_BOT_TOKEN_set: !!cfg.TELEGRAM_BOT_TOKEN,
    COOKMYBOTS_AI_ENDPOINT_set: !!cfg.COOKMYBOTS_AI_ENDPOINT,
    COOKMYBOTS_AI_KEY_set: !!cfg.COOKMYBOTS_AI_KEY,
    MONGODB_URI_set: !!cfg.MONGODB_URI
  });

  if (!cfg.TELEGRAM_BOT_TOKEN) {
    console.error("TELEGRAM_BOT_TOKEN is required. Add it to your env and redeploy.");
    process.exit(1);
  }

  if (!cfg.COOKMYBOTS_AI_ENDPOINT || !cfg.COOKMYBOTS_AI_KEY) {
    console.error("COOKMYBOTS_AI_ENDPOINT and COOKMYBOTS_AI_KEY are required for translation.");
    process.exit(1);
  }

  const { createBot } = await import("./bot.js");
  const { registerCommands } = await import("./commands/loader.js");

  const bot = createBot(cfg.TELEGRAM_BOT_TOKEN);

  bot.catch((err) => {
    log.error("[bot] error", { err: safeErr(err?.error || err) });
  });

  try {
    await bot.init();
  } catch (e) {
    log.warn("[boot] bot.init failed (continuing)", { err: safeErr(e) });
  }

  await registerCommands(bot);

  try {
    await bot.api.setMyCommands([
      { command: "start", description: "Welcome & examples" },
      { command: "help", description: "How to use" },
      { command: "auto_on", description: "Enable auto-translate" },
      { command: "auto_off", description: "Disable auto-translate" },
      { command: "toen", description: "Force translation to English" },
      { command: "toid", description: "Force translation to Indonesian" },
      { command: "mode", description: "Show current chat mode" }
    ]);
  } catch (e) {
    log.warn("[boot] setMyCommands failed", { err: safeErr(e) });
  }

  // Memory log once per minute
  setInterval(() => {
    const m = process.memoryUsage();
    console.log("[mem]", {
      rssMB: Math.round(m.rss / 1e6),
      heapUsedMB: Math.round(m.heapUsed / 1e6)
    });
  }, 60_000).unref();

  await startPolling(bot);
}

boot().catch(async (e) => {
  log.error("[boot] failed", { err: safeErr(e) });
  if (!restarting) {
    restarting = true;
    await sleep(2000);
    process.exit(1);
  }
});

ai.js.content:
import { cfg } from "./config.js";
import { log } from "./log.js";
import { safeErr } from "./safeErr.js";

function trimSlash(u) {
  u = String(u || "");
  while (u.endsWith("/")) u = u.slice(0, -1);
  return u;
}

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

function withTimeout(ms) {
  const ctrl = new AbortController();
  const t = setTimeout(() => ctrl.abort(), ms);
  return { ctrl, clear: () => clearTimeout(t) };
}

function getTimeoutMs(override) {
  const v = Number(override || cfg.AI_TIMEOUT_MS || 600000);
  return Number.isFinite(v) && v > 0 ? v : 600000;
}

function getRetries(override) {
  const v = Number.isFinite(override) ? Number(override) : Number(cfg.AI_MAX_RETRIES || 2);
  return Number.isFinite(v) && v >= 0 ? v : 2;
}

function isRetryableStatus(status) {
  return status === 408 || status === 429 || (status >= 500 && status <= 599);
}

async function safeReadJson(r) {
  const text = await r.text();
  let json = null;
  try {
    json = JSON.parse(text);
  } catch {}
  return { text, json };
}

export async function aiChat({ messages, meta = {} }, opts = {}) {
  const base = trimSlash(cfg.COOKMYBOTS_AI_ENDPOINT || "");
  const key = String(cfg.COOKMYBOTS_AI_KEY || "");

  if (!base || !key) {
    const err = "AI_NOT_CONFIGURED (missing COOKMYBOTS_AI_ENDPOINT/COOKMYBOTS_AI_KEY)";
    return { ok: false, status: 412, json: null, error: err };
  }

  const timeoutMs = getTimeoutMs(opts.timeoutMs);
  const retries = getRetries(opts.retries);

  const url = base + "/chat";

  const started = Date.now();
  log.info("[ai] chat start", {
    feature: "translate",
    timeoutMs,
    retries,
    endpointSet: true,
    keySet: true
  });

  let attempt = 0;
  while (true) {
    attempt++;
    const { ctrl, clear } = withTimeout(timeoutMs);
    try {
      const r = await fetch(url, {
        method: "POST",
        headers: {
          Authorization: "Bearer " + key,
          "Content-Type": "application/json"
        },
        body: JSON.stringify({ messages, meta }),
        signal: ctrl.signal
      });

      const { json, text } = await safeReadJson(r);

      if (!r.ok) {
        const msg = json?.error || json?.message || text || "AI_ERROR";
        log.warn("[ai] chat fail", { status: r.status, attempt, err: String(msg).slice(0, 300) });
        if (attempt <= retries && isRetryableStatus(r.status)) {
          await sleep(500 * attempt);
          continue;
        }
        return { ok: false, status: r.status, json, error: String(msg) };
      }

      const latencyMs = Date.now() - started;
      log.info("[ai] chat success", { latencyMs, attempt });
      return { ok: true, status: r.status, json, error: null };
    } catch (e) {
      const msg = safeErr(e);
      const status = e?.name === "AbortError" ? 408 : 0;
      log.warn("[ai] chat exception", { status, attempt, err: String(msg).slice(0, 300) });
      if (attempt <= retries && (status === 0 || status === 408)) {
        await sleep(500 * attempt);
        continue;
      }
      return { ok: false, status, json: null, error: String(msg) };
    } finally {
      clear();
    }
  }
}

