import { MongoClient } from "mongodb";
import { log } from "./log.js";
import { safeErr } from "./safeErr.js";

let _client = null;
let _db = null;
let _ensured = false;

export async function getDb(mongoUri) {
  if (!mongoUri) return null;
  if (_db) return _db;

  try {
    _client = new MongoClient(mongoUri, { maxPoolSize: 5 });
    await _client.connect();
    _db = _client.db();

    log.info("[db] connected", { mongoConfigured: true });

    if (!_ensured) {
      _ensured = true;
      await ensureIndexes(_db);
    }

    return _db;
  } catch (e) {
    log.error("[db] connect failed", { err: safeErr(e) });
    _client = null;
    _db = null;
    return null;
  }
}

async function ensureIndexes(db) {
  try {
    await db.collection("chat_settings").createIndex({ chatId: 1 }, { unique: true });
  } catch (e) {
    log.warn("[db] ensureIndexes failed", { err: safeErr(e) });
  }
}

log.js.content:
import { cfg } from "./config.js";

const levelOrder = {
  debug: 10,
  info: 20,
  warn: 30,
  error: 40
};

function shouldLog(level) {
  const cur = levelOrder[cfg.LOG_LEVEL] ?? levelOrder.info;
  return (levelOrder[level] ?? 999) >= cur;
}

export const log = {
  debug: (msg, meta = undefined) => {
    if (!shouldLog("debug")) return;
    console.log("[debug]", msg, meta || "");
  },
  info: (msg, meta = undefined) => {
    if (!shouldLog("info")) return;
    console.log("[info]", msg, meta || "");
  },
  warn: (msg, meta = undefined) => {
    if (!shouldLog("warn")) return;
    console.warn("[warn]", msg, meta || "");
  },
  error: (msg, meta = undefined) => {
    if (!shouldLog("error")) return;
    console.error("[error]", msg, meta || "");
  }
};

