export function safeErr(err) {
  return (
    err?.response?.data?.error?.message ||
    err?.response?.data?.message ||
    err?.message ||
    String(err)
  );
}

rateLimit.js.content:
const buckets = new Map();

function nowMs() {
  return Date.now();
}

export function rateLimitMiddleware({ limit = 5, windowMs = 10_000 } = {}) {
  return async (ctx, next) => {
    const userId = ctx.from?.id ? String(ctx.from.id) : "";
    if (!userId) return next();

    const now = nowMs();
    const b = buckets.get(userId) || { start: now, count: 0, warnedAt: 0 };

    if (now - b.start > windowMs) {
      b.start = now;
      b.count = 0;
    }

    b.count += 1;
    buckets.set(userId, b);

    if (b.count > limit) {
      if (now - (b.warnedAt || 0) > windowMs) {
        b.warnedAt = now;
        buckets.set(userId, b);
        try {
          await ctx.reply("You're sending too fast. Please wait a few seconds.");
        } catch {}
      }
      return;
    }

    return next();
  };
}

chatSettings.js.content:
const log = {
  info:  (...a) => console.log(...a),
  warn:  (...a) => console.warn(...a),
  error: (...a) => console.error(...a),
};

import { getDb } from "../lib/db.js";
import { cfg } from "../lib/config.js";

import { safeErr } from "../lib/safeErr.js";

const COL = "chat_settings";

export function defaultChatSettings(chatId) {
  return {
    chatId: String(chatId),
    autoTranslate: true,
    directionMode: "auto" // "auto" | "toen" | "toid"
  };
}

export async function getChatSettings(chatId) {
  const id = String(chatId);
  const db = await getDb(cfg.MONGODB_URI);
  if (!db) return { settings: defaultChatSettings(id), persisted: false };

  try {
    const row = await db.collection(COL).findOne({ chatId: id });
    if (!row) {
      const def = defaultChatSettings(id);
      await db.collection(COL).updateOne(
        { chatId: id },
        {
          $setOnInsert: { createdAt: new Date() },
          $set: { ...def, updatedAt: new Date() }
        },
        { upsert: true }
      );
      return { settings: def, persisted: true };
    }

    return {
      settings: {
        chatId: id,
        autoTranslate: row.autoTranslate !== false,
        directionMode: row.directionMode === "toen" || row.directionMode === "toid" ? row.directionMode : "auto"
      },
      persisted: true
    };
  } catch (e) {
    log.error("[db] read failed", { col: COL, op: "findOne", err: safeErr(e) });
    return { settings: defaultChatSettings(id), persisted: false };
  }
}

export async function updateChatSettings(chatId, patch) {
  const id = String(chatId);
  const db = await getDb(cfg.MONGODB_URI);
  if (!db) {
    return { ok: false, error: "DB_NOT_CONFIGURED" };
  }

  const mutable = { ...patch };
  delete mutable._id;
  delete mutable.createdAt;

  try {
    await db.collection(COL).updateOne(
      { chatId: id },
      {
        $setOnInsert: { },
        $set: { ...mutable, chatId: id, updatedAt: new Date() }
      },
      { upsert: true }
    );
    return { ok: true };
  } catch (e) {
    log.error("[db] write failed", { col: COL, op: "updateOne", err: safeErr(e) });
    return { ok: false, error: safeErr(e) };
  }
}

translate.js.content:
import { aiChat } from "../lib/ai.js";

function clampText(s) {
  const t = String(s || "");
  if (t.length <= 3500) return t;
  return t.slice(0, 3500);
}

function directionLabel(targetLang) {
  return targetLang === "en" ? "ID → EN" : "EN → ID";
}

export async function translateText({ botProfile, text, directionMode }) {
  const t = clampText(text);

  const targetHint =
    directionMode === "toen" ? "en" :
    directionMode === "toid" ? "id" :
    "auto";

  const system =
    String(botProfile || "") +
    "\n\n" +
    "Task: Translate chat messages between Indonesian (id) and English (en)." +
    "\n" +
    "Rules:" +
    "\n" +
    "1) Detect whether the input text is Indonesian or English." +
    "\n" +
    "2) If target is auto: translate to the opposite language. If detection is uncertain, translate into English." +
    "\n" +
    "3) If target is forced (en or id), translate into that target language." +
    "\n" +
    "4) Return ONLY the translated text. No labels, no quotes, no explanations.";

  const user =
    "Target: " + targetHint + "\n" +
    "Text:\n" + t;

  const res = await aiChat({
    messages: [
      { role: "system", content: system },
      { role: "user", content: user }
    ],
    meta: { platform: "telegram", purpose: "translate", target: targetHint }
  });

  if (!res.ok) {
    return { ok: false, error: res.error || "AI_ERROR" };
  }

  const content = res?.json?.output?.content;
  const out = String(content || "").trim();
  if (!out) return { ok: false, error: "EMPTY_TRANSLATION" };

  let label = "";
  if (directionMode === "toen") label = directionLabel("en");
  else if (directionMode === "toid") label = directionLabel("id");
  else {
    // For auto mode, infer label heuristically to match the prompt's intent.
    // If output contains many Indonesian stop words, assume EN->ID; else ID->EN.
    const lower = out.toLowerCase();
    const idHints = [" yang ", " tidak ", " saya ", " kamu ", " ini ", " itu ", " dan ", " di ", " ke "];
    const idScore = idHints.reduce((n, w) => n + (lower.includes(w) ? 1 : 0), 0);
    label = idScore >= 2 ? directionLabel("id") : directionLabel("en");
  }

  return { ok: true, translatedText: out, label };
}
